<?php namespace App\Repositories\Attendance;use App\Repositories\BaseRepository;use App\Models\Attendance\LeaveBalance;use Illuminate\Database\Eloquent\Collection;class LeaveBalanceRepository extends BaseRepository{    public function __construct(LeaveBalance $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findByLeaveType(int $leaveTypeId): Collection    {        return $this->findByField('leave_type_id', $leaveTypeId);    }    public function findByEmployeeAndLeaveType(int $employeeId, int $leaveTypeId): ?LeaveBalance    {        return $this->query()->where('employee_id', $employeeId)->where('leave_type_id', $leaveTypeId)->first();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function deductLeave(int $employeeId, int $leaveTypeId, int $days): bool    {        $balance = $this->findByEmployeeAndLeaveType($employeeId, $leaveTypeId);        if ($balance && $balance->balance >= $days) {            return $this->update($balance->id, [                'balance' => $balance->balance - $days,                'used' => ($balance->used ?? 0) + $days,            ]);        }        return false;    }    public function getEmployeesWithLowBalance(int $threshold = 2): Collection    {        return $this->query()->where('balance', '<=', $threshold)->get();    }    public function resetAnnualBalance(int $employeeId, int $leaveTypeId, float $totalDays): LeaveBalance    {        $balance = $this->findByEmployeeAndLeaveType($employeeId, $leaveTypeId);        if ($balance) {            $this->update($balance->id, ['balance' => $totalDays, 'used' => 0]);            return $balance->fresh();        }        return $this->create([            'employee_id' => $employeeId,            'leave_type_id' => $leaveTypeId,            'total_days' => $totalDays,            'balance' => $totalDays,            'used' => 0,        ]);    }    public function getAvailableBalance(int $employeeId, int $leaveTypeId): float    {        $balance = $this->findByEmployeeAndLeaveType($employeeId, $leaveTypeId);        return $balance ? $balance->balance : 0;    }}